12→export function SwingCanvas({ className }: SwingCanvasProps) {
13→  const containerRef = useRef<HTMLDivElement>(null);
14→  const canvasRef = useRef<HTMLCanvasElement>(null);
15→  const framesRef = useRef<HTMLImageElement[]>([]);
16→  const rafRef = useRef<number>(0);
17→  const currentFrameRef = useRef<number>(0);
18→
19→  const [loaded, setLoaded] = useState(false);
20→  const [progress, setProgress] = useState(0);
21→  const prefersReducedMotion = useReducedMotion();
22→
23→  const drawFrame = useCallback((index: number) => {
24→    const canvas = canvasRef.current;
25→    const frames = framesRef.current;
26→    if (!canvas || !frames.length) return;
27→
28→    const ctx = canvas.getContext("2d");
29→    if (!ctx) return;
30→
31→    const frame = frames[Math.min(index, frames.length - 1)];
32→    if (!frame) return;
33→
34→    // Size canvas to container
35→    const container = containerRef.current;
36→    if (!container) return;
37→
38→    const rect = container.getBoundingClientRect();
39→    const dpr = window.devicePixelRatio || 1;
40→
41→    // Set canvas drawing size
42→    canvas.width = rect.width * dpr;
43→    canvas.height = rect.height * dpr;
44→
45→    // Set canvas display size
46→    canvas.style.width = `${rect.width}px`;
47→    canvas.style.height = `${rect.height}px`;
48→
49→    ctx.scale(dpr, dpr);
50→    ctx.clearRect(0, 0, rect.width, rect.height);

