 1→import fs from "fs";
 2→import path from "path";
 3→import matter from "gray-matter";
 4→import { compileMDX } from "next-mdx-remote/rsc";
 5→import rehypePrettyCode from "rehype-pretty-code";
 6→
 7→const CONTENT_DIR = path.join(process.cwd(), "src/content/blog");
 8→
 9→export interface PostMeta {
10→  slug: string;
11→  title: string;
12→  date: string;
13→  excerpt: string;
14→  tags: string[];
15→}
16→
17→export interface Post {
18→  meta: PostMeta;
19→  content: React.ReactElement;
20→}
21→
22→function parseFrontmatter(slug: string): PostMeta {
23→  const filePath = path.join(CONTENT_DIR, `${slug}.mdx`);
24→  const raw = fs.readFileSync(filePath, "utf-8");
25→  const { data } = matter(raw);
26→
27→  return {
28→    slug,
29→    title: data.title ?? "",
30→    date: data.date ?? "",
31→    excerpt: data.excerpt ?? "",
32→    tags: data.tags ?? [],
33→  };
34→}
35→
36→export function getAllPosts(): PostMeta[] {
37→  if (!fs.existsSync(CONTENT_DIR)) return [];
38→
39→  const files = fs.readdirSync(CONTENT_DIR).filter((f) => f.endsWith(".mdx"));
40→
41→  return files
42→    .map((file) => parseFrontmatter(file.replace(/\.mdx$/, "")))
43→    .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
44→}
45→
46→export async function getPostBySlug(slug: string): Promise<Post> {
47→  const filePath = path.join(CONTENT_DIR, `${slug}.mdx`);
48→  const raw = fs.readFileSync(filePath, "utf-8");
49→  const { content, data } = matter(raw);
50→
51→  const { content: mdxContent } = await compileMDX({
52→    source: content,
53→    options: {
54→      mdxOptions: {
55→        rehypePlugins: [
56→          [
57→            rehypePrettyCode,
58→            {
59→              theme: "one-dark-pro",
60→              keepBackground: true,
61→            },
62→          ],
63→        ],
64→      },
65→    },
66→  });
67→
68→  return {
69→    meta: {
70→      slug,
71→      title: data.title ?? "",
72→      date: data.date ?? "",
73→      excerpt: data.excerpt ?? "",
74→      tags: data.tags ?? [],
75→    },
76→    content: mdxContent,
77→  };
78→}
