  1→import { NextRequest, NextResponse } from "next/server";
  2→import { createAgent } from "@/lib/agent/graph";
  3→import { HumanMessage, AIMessage } from "@langchain/core/messages";
  4→
  5→export async function POST(request: NextRequest) {
  6→  if (!process.env.XAI_API_KEY) {
  7→    return NextResponse.json(
  8→      { error: "XAI_API_KEY not configured" },
  9→      { status: 500 }
 10→    );
 11→  }
 12→
 13→  let body: { messages: { role: string; content: string }[] };
 14→  try {
 15→    body = await request.json();
 16→  } catch {
 17→    return NextResponse.json({ error: "Invalid JSON" }, { status: 400 });
 18→  }
 19→
 20→  if (!body.messages || !Array.isArray(body.messages)) {
 21→    return NextResponse.json(
 22→      { error: "messages array required" },
 23→      { status: 400 }
 24→    );
 25→  }
 26→
 27→  const agent = createAgent();
 28→
 29→  // Convert client messages to LangChain format
 30→  const langchainMessages = body.messages.map(
 31→    (m: { role: string; content: string }) => {
 32→      if (m.role === "user") {
 33→        return new HumanMessage(m.content);
 34→      }
 35→      return new AIMessage(m.content);
 36→    }
 37→  );
 38→
 39→  const encoder = new TextEncoder();
 40→
 41→  const stream = new ReadableStream({
 42→    async start(controller) {
 43→      try {
 44→        let navigateRoute: string | null = null;
 45→        let openResume = false;
 46→
 47→        const eventStream = agent.streamEvents(
 48→          { messages: langchainMessages },
 49→          { version: "v2" }
 50→        );
 51→
 52→        for await (const event of eventStream) {
 53→          // Stream text content from the LLM
 54→          if (event.event === "on_chat_model_stream") {
 55→            const content = event.data.chunk?.content;
 56→            if (content && typeof content === "string") {
 57→              controller.enqueue(
 58→                encoder.encode(
 59→                  JSON.stringify({ type: "text", content }) + "\n"
 60→                )
 61→              );
 62→            }
 63→          }
 64→
 65→          // Capture tool actions
 66→          if (event.event === "on_tool_end") {
 67→            try {
 68→              const output =
 69→                typeof event.data.output === "string"
 70→                  ? event.data.output
 71→                  : event.data.output?.content
 72→                    ? String(event.data.output.content)
 73→                    : String(event.data.output);
 74→              const parsed = JSON.parse(output);
 75→              if (parsed.action === "navigate") {
 76→                navigateRoute = parsed.route;
 77→              } else if (parsed.action === "open_resume") {
 78→                openResume = true;
 79→              }
 80→            } catch {
 81→              // Tool output wasn't parseable - ignore
 82→            }
 83→          }
 84→        }
 85→
 86→        // Send action events after text is complete
 87→        if (navigateRoute) {
 88→          controller.enqueue(
 89→            encoder.encode(
 90→              JSON.stringify({ type: "navigate", route: navigateRoute }) + "\n"
 91→            )
 92→          );
 93→        }
 94→        if (openResume) {
 95→          controller.enqueue(
 96→            encoder.encode(
 97→              JSON.stringify({ type: "open_resume", url: "/cameron-keith-resume.pdf" }) + "\n"
 98→            )
 99→          );
100→        }
101→
102→        controller.enqueue(
103→          encoder.encode(JSON.stringify({ type: "done" }) + "\n")
104→        );
105→      } catch {
106→        controller.enqueue(
107→          encoder.encode(
108→            JSON.stringify({
109→              type: "error",
110→              message: "Something went wrong. Please try again.",
111→            }) + "\n"
112→          )
113→        );
114→      } finally {
115→        controller.close();
116→      }
117→    },
118→  });
119→
120→  return new Response(stream, {
121→    headers: {
122→      "Content-Type": "text/plain; charset=utf-8",
123→      "Cache-Control": "no-cache",
124→    },
125→  });
126→}
